        latitude: 50,
        longitude: 30,
        placeName: 'Lake',
        description: 'cloudy',
        temperatureCelsius: 18,
        feelsLikeCelsius: 17,
        pressureHpa: 1010,
        humidityPercent: 70,
        windSpeedMs: 3,
        windDirectionDegrees: 180,
        fetchedAt: '10:00',
      ),
      WeatherSnapshot(
        latitude: 50,
        longitude: 30,
        placeName: 'Lake',
        description: 'windy',
        temperatureCelsius: 20,
        feelsLikeCelsius: 18,
        pressureHpa: 1008,
        humidityPercent: 65,
        windSpeedMs: 5,
        windDirectionDegrees: 200,
        fetchedAt: '10:15',
      ),
    ]);

    await _pump(tester, session);

    expect(find.text('Weather during match'), findsOneWidget);
    expect(find.textContaining('temp up 2.0'), findsOneWidget);
    expect(find.textContaining('pressure down 2.0'), findsOneWidget);
    expect(find.textContaining('max wind 5.0 m/s'), findsOneWidget);
