  GameSession copyWith({
    String? name,
    String? venue,
    String? sectorPeg,
    String? trainingType,
    String? fishingMethod,
    String? targetPace,
    String? speciesPreset,
    String? bodyTypePreset,
    String? conditions,
    String? baitNotes,
    String? athleteName,
    String? coachName,
    String? athleteNote,
    String? coachComment,
    double? finalWeightKg,
    int? finalCount,
    bool clearFinalWeight = false,
    bool clearFinalCount = false,
    String? updatedAt,
    SessionUserInfo? userInfo,
    SessionVenueInfo? venueInfo,
    SessionGoals? goals,
    AstronomyInfo? astronomyInfo,
    WeatherInfo? weatherInfo,
    List<WeatherSnapshot>? weatherSnapshots,
  }) {
    return GameSession._(
      id: id,
      name: name ?? this.name,
      date: date,
      c1: c1,
      c2: c2,
      tries: tries,
      total: total,
      finalWeightKg: clearFinalWeight ? null : finalWeightKg ?? this.finalWeightKg,
      finalCount: clearFinalCount ? null : finalCount ?? this.finalCount,
      matchDuration: matchDuration,
      grid: List<Map<String, dynamic>>.from(grid),
      userInfo: userInfo ?? this.userInfo,
      venueInfo: venueInfo ??
          (venue == null &&
                  sectorPeg == null &&
                  trainingType == null &&
                  fishingMethod == null &&
                  targetPace == null &&
                  speciesPreset == null &&
                  bodyTypePreset == null &&
                  conditions == null &&
                  baitNotes == null
              ? this.venueInfo
              : this.venueInfo.copyWith(
                  venue: venue,
                  sectorPeg: sectorPeg,
                  trainingType: trainingType,
                  fishingMethod: fishingMethod,
                  targetPace: targetPace,
                  speciesPreset: speciesPreset,
                  bodyTypePreset: bodyTypePreset,
                  conditions: conditions,
                  baitNotes: baitNotes,
                )),
      goals: goals ?? this.goals,
      astronomyInfo: astronomyInfo ?? this.astronomyInfo,
      weatherInfo: weatherInfo ?? this.weatherInfo,
      weatherSnapshots: weatherSnapshots ?? this.weatherSnapshots,
      updatedAt: updatedAt ?? this.updatedAt,
      athleteName: athleteName ?? this.athleteName,
      coachName: coachName ?? this.coachName,
      athleteNote: athleteNote ?? this.athleteNote,
      coachComment: coachComment ?? this.coachComment,
    );
  }

  Map<String, dynamic> toJson() => {
    'id': id,
    'name': name,
    'date': date,
    'c1': c1,
    'c2': c2,
    'tries': tries,
    'total': total,
    'finalWeightKg': finalWeightKg,
    'finalCount': finalCount,
    'matchDuration': matchDuration,
    'grid': grid,
    'athleteName': athleteName,
    'coachName': coachName,
    'updatedAt': updatedAt,
    'athleteNote': athleteNote,
    'coachComment': coachComment,
    ...userInfo.toJson(),
    ...venueInfo.toJson(),
    ...goals.toJson(),
    ...astronomyInfo.toJson(),
    ...weatherInfo.toJson(),
    'weatherSnapshots': weatherSnapshots.map((snapshot) => snapshot.toJson()).toList(),
  };

  factory GameSession.fromJson(Map<String, dynamic> json) {
    return GameSession._(
      id: TypeUtils.safeString(json['id']),
      name: TypeUtils.safeString(json['name'], defaultValue: 'Session'),
      date: TypeUtils.safeString(json['date'], defaultValue: '--'),
      c1: TypeUtils.safeInt(json['c1']),
      c2: TypeUtils.safeInt(json['c2']),
      tries: TypeUtils.safeInt(json['tries']),
      total: TypeUtils.safeInt(json['total']),
      finalWeightKg: TypeUtils.safeDouble(json['finalWeightKg']),
      finalCount: json.containsKey('finalCount') ? TypeUtils.safeInt(json['finalCount']) : null,
      matchDuration: TypeUtils.safeString(
        json['matchDuration'],
        defaultValue: '00:00:00',
      ),
      grid: TypeUtils.safeMapList(json['grid']),
      userInfo: SessionUserInfo.fromJson(json),
      venueInfo: SessionVenueInfo.fromJson(json),
      goals: SessionGoals.fromJson(json),
      astronomyInfo: AstronomyInfo.fromJson(json),
      weatherInfo: WeatherInfo.fromJson(json),
      weatherSnapshots: _parseWeatherSnapshots(json['weatherSnapshots']),
      updatedAt: TypeUtils.safeString(
        json['updatedAt'],
        defaultValue: TypeUtils.safeString(json['id']),
      ),
      athleteName: TypeUtils.safeString(json['athleteName']),
      coachName: TypeUtils.safeString(json['coachName']),
      athleteNote: TypeUtils.safeString(json['athleteNote']),
      coachComment: TypeUtils.safeString(json['coachComment']),
    );
  }

  static List<WeatherSnapshot> _parseWeatherSnapshots(dynamic value) {
    if (value is! List) return const [];
    return value
        .whereType<Map>()
        .map((entry) => WeatherSnapshot.fromJson(Map<String, dynamic>.from(entry)))
        .toList();
  }
}

